"""
Parameterized generator for GH798_tower_603.

Source PR:    https://github.com/tower-rs/tower/pull/603
Source Issue: N/A

Seed varies: renames 'alloc' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH798_tower_603'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH798_tower_603'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('alloc', 'alloc' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH798_tower_603',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'tower-rs/tower',
                "pr_number": 603,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/tower-rs/tower/pull/603",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'tower-layer/Cargo.toml': '[package]\nname = "tower-layer"\n# When releasing to crates.io:\n# - Remove path dependencies\n# - Update html_root_url.\n# - Update doc url\n#   - Cargo.toml\n#   - README.md\n# - Update CHANGELOG.md.\n# - Create "v0.1.x" git tag.\nversion = "0.3.1"\nauthors = ["Tower Maintainers <team@tower-rs.com>"]\nlicense = "MIT"\nreadme = "README.md"\nrepository = "https://github.com/tower-rs/tower"\nhomepage = "https://github.com/tower-rs/tower"\ndocumentation = "https://docs.rs/tower-layer/0.3.0-alpha.2"\ndescription = """\nDecorates a `Service` to allow easy composition between `Service`s.\n"""\ncategories = ["asynchronous", "network-programming"]\nedition = "2018"\n\n[dependencies]\n\n[dev-dependencies]\ntower-service = { version = "0.3.0", path = "../tower-service" }\ntower = { version = "0.4", path = "../tower" }\n',
            'tower-layer/src/lib.rs': '#![doc(html_root_url = "https://docs.rs/tower-layer/0.3.1")]\n#![warn(\n    missing_debug_implementations,\n    missing_docs,\n    rust_2018_idioms,\n    unreachable_pub\n)]\n#![forbid(unsafe_code)]\n// `rustdoc::broken_intra_doc_links` is checked on CI\n\n//! Layer traits and extensions.\n//!\n//! A layer decorates an service and provides additional functionality. It\n//! allows other services to be composed with the service that implements layer.\n//!\n//! A middleware implements the [`Layer`] and [`Service`] trait.\n//!\n//! [`Service`]: https://docs.rs/tower/trait.Service.html\n\nmod identity;\nmod layer_fn;\nmod stack;\n\npub use self::{\n    identity::Identity,\n    layer_fn::{layer_fn, LayerFn},\n    stack::Stack,\n};\n\n/// Decorates a [`Service`], transforming either the request or the response.\n///\n/// Often, many of the pieces needed for writing network applications can be\n/// reused across multiple services. The `Layer` trait can be used to write\n/// reusable components that can be applied to very different kinds of services;\n/// for example, it can be applied to services operating on different protocols,\n/// and to both the client and server side of a network transaction.\n///\n/// # Log\n///\n/// Take request logging as an example:\n///\n/// ```rust\n/// # use tower_service::Service;\n/// # use std::task::{Poll, Context};\n/// # use tower_layer::Layer;\n/// # use std::fmt;\n///\n/// pub struct LogLayer {\n///     target: &\'static str,\n/// }\n///\n/// impl<S> Layer<S> for LogLayer {\n///     type Service = LogService<S>;\n///\n///     fn layer(&self, service: S) -> Self::Service {\n///         LogService {\n///             target: self.target,\n///             service\n///         }\n///     }\n/// }\n///\n/// // This service implements the Log behavior\n/// pub struct LogService<S> {\n///     target: &\'static str,\n///     service: S,\n/// }\n///\n/// impl<S, Request> Service<Request> for LogService<S>\n/// where\n///     S: Service<Request>,\n///     Request: fmt::Debug,\n/// {\n///     type Response = S::Response;\n///     type Error = S::Error;\n///     type Future = S::Future;\n///\n///     fn poll_ready(&mut self, cx: &mut Context<\'_>) -> Poll<Result<(), Self::Error>> {\n///         self.service.poll_ready(cx)\n///     }\n///\n///     fn call(&mut self, request: Request) -> Self::Future {\n///         // Insert log statement here or other functionality\n///         println!("request = {:?}, target = {:?}", request, self.target);\n///         self.service.call(request)\n///     }\n/// }\n/// ```\n///\n/// The above log implementation is decoupled from the underlying protocol and\n/// is also decoupled from client or server concerns. In other words, the same\n/// log middleware could be used in either a client or a server.\n///\n/// [`Service`]: https://docs.rs/tower/trait.Service.html\npub trait Layer<S> {\n    /// The wrapped service\n    type Service;\n    /// Wrap the given service with the middleware, returning a new service\n    /// that has been decorated with the middleware.\n    fn layer(&self, inner: S) -> Self::Service;\n}\n\nimpl<\'a, T, S> Layer<S> for &\'a T\nwhere\n    T: ?Sized + Layer<S>,\n{\n    type Service = T::Service;\n\n    fn layer(&self, inner: S) -> Self::Service {\n        (**self).layer(inner)\n    }\n}\n',
            'tower-service/Cargo.toml': '[package]\nname = "tower-service"\n# When releasing to crates.io:\n# - Remove path dependencies\n# - Update html_root_url.\n# - Update doc url\n#   - Cargo.toml\n#   - README.md\n# - Update CHANGELOG.md.\n# - Create "v0.2.x" git tag.\nversion = "0.3.1"\nauthors = ["Tower Maintainers <team@tower-rs.com>"]\nlicense = "MIT"\nreadme = "README.md"\nrepository = "https://github.com/tower-rs/tower"\nhomepage = "https://github.com/tower-rs/tower"\ndocumentation = "https://docs.rs/tower-service/0.3.1"\ndescription = """\nTrait representing an asynchronous, request / response based, client or server.\n"""\ncategories = ["asynchronous", "network-programming"]\nedition = "2018"\n\n[dependencies]\n\n[dev-dependencies]\nhttp = "0.2"\ntower-layer = { version = "0.3", path = "../tower-layer" }\ntokio = { version = "1", features = ["macros", "time"] }\nfutures = "0.3"\n',
            'tower-service/src/lib.rs': '#![doc(html_root_url = "https://docs.rs/tower-service/0.3.1")]\n#![warn(\n    missing_debug_implementations,\n    missing_docs,\n    rust_2018_idioms,\n    unreachable_pub\n)]\n#![forbid(unsafe_code)]\n// `rustdoc::broken_intra_doc_links` is checked on CI\n\n//! Definition of the core `Service` trait to Tower\n//!\n//! The [`Service`] trait provides the necessary abstractions for defining\n//! request / response clients and servers. It is simple but powerful and is\n//! used as the foundation for the rest of Tower.\n\nuse std::future::Future;\nuse std::task::{Context, Poll};\n\n/// An asynchronous function from a `Request` to a `Response`.\n///\n/// The `Service` trait is a simplified interface making it easy to write\n/// network applications in a modular and reusable way, decoupled from the\n/// underlying protocol. It is one of Tower\'s fundamental abstractions.\n///\n/// # Functional\n///\n/// A `Service` is a function of a `Request`. It immediately returns a\n/// `Future` representing the eventual completion of processing the\n/// request. The actual request processing may happen at any time in the\n/// future, on any thread or executor. The processing may depend on calling\n/// other services. At some point in the future, the processing will complete,\n/// and the `Future` will resolve to a response or error.\n///\n/// At a high level, the `Service::call` function represents an RPC request. The\n/// `Service` value can be a server or a client.\n///\n/// # Server\n///\n/// An RPC server *implements* the `Service` trait. Requests received by the\n/// server over the network are deserialized and then passed as an argument to the\n/// server value. The returned response is sent back over the network.\n///\n/// As an example, here is how an HTTP request is processed by a server:\n///\n/// ```rust\n/// # use std::pin::Pin;\n/// # use std::task::{Poll, Context};\n/// # use std::future::Future;\n/// # use tower_service::Service;\n/// use http::{Request, Response, StatusCode};\n///\n/// struct HelloWorld;\n///\n/// impl Service<Request<Vec<u8>>> for HelloWorld {\n///     type Response = Response<Vec<u8>>;\n///     type Error = http::Error;\n///     type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>>>>;\n///\n///     fn poll_ready(&mut self, cx: &mut Context<\'_>) -> Poll<Result<(), Self::Error>> {\n///         Poll::Ready(Ok(()))\n///     }\n///\n///     fn call(&mut self, req: Request<Vec<u8>>) -> Self::Future {\n///         // create the body\n///         let body: Vec<u8> = "hello, world!\\n"\n///             .as_bytes()\n///             .to_owned();\n///         // Create the HTTP response\n///         let resp = Response::builder()\n///             .status(StatusCode::OK)\n///             .body(body)\n///             .expect("Unable to create `http::Response`");\n///\n///         // create a response in a future.\n///         let fut = async {\n///             Ok(resp)\n///         };\n///\n///         // Return the response as an immediate future\n///         Box::pin(fut)\n///     }\n/// }\n/// ```\n///\n/// # Client\n///\n/// A client consumes a service by using a `Service` value. The client may\n/// issue requests by invoking `call` and passing the request as an argument.\n/// It then receives the response by waiting for the returned future.\n///\n/// As an example, here is how a Redis request would be issued:\n///\n/// ```rust,ignore\n/// let client = redis::Client::new()\n///     .connect("127.0.0.1:6379".parse().unwrap())\n///     .unwrap();\n///\n/// let resp = client.call(Cmd::set("foo", "this is the value of foo")).await?;\n///\n/// // Wait for the future to resolve\n/// println!("Redis response: {:?}", resp);\n/// ```\n///\n/// # Middleware / Layer\n///\n/// More often than not, all the pieces needed for writing robust, scalable\n/// network applications are the same no matter the underlying protocol. By\n/// unifying the API for both clients and servers in a protocol agnostic way,\n/// it is possible to write middleware that provide these pieces in a\n/// reusable way.\n///\n/// Take timeouts as an example:\n///\n/// ```rust\n/// use tower_service::Service;\n/// use tower_layer::Layer;\n/// use futures::FutureExt;\n/// use std::future::Future;\n/// use std::task::{Context, Poll};\n/// use std::time::Duration;\n/// use std::pin::Pin;\n/// use std::fmt;\n/// use std::error::Error;\n///\n/// // Our timeout service, which wraps another service and\n/// // adds a timeout to its response future.\n/// pub struct Timeout<T> {\n///     inner: T,\n///     timeout: Duration,\n/// }\n///\n/// impl<T> Timeout<T> {\n///     pub fn new(inner: T, timeout: Duration) -> Timeout<T> {\n///         Timeout {\n///             inner,\n///             timeout\n///         }\n///     }\n/// }\n///\n/// // The error returned if processing a request timed out\n/// #[derive(Debug)]\n/// pub struct Expired;\n///\n/// impl fmt::Display for Expired {\n///     fn fmt(&self, f: &mut fmt::Formatter<\'_>) -> fmt::Result {\n///         write!(f, "expired")\n///     }\n/// }\n///\n/// impl Error for Expired {}\n///\n/// // We can implement `Service` for `Timeout<T>` if `T` is a `Service`\n/// impl<T, Request> Service<Request> for Timeout<T>\n/// where\n///     T: Service<Request>,\n///     T::Future: \'static,\n///     T::Error: Into<Box<dyn Error + Send + Sync>> + \'static,\n///     T::Response: \'static,\n/// {\n///     // `Timeout` doesn\'t modify the response type, so we use `T`\'s response type\n///     type Response = T::Response;\n///     // Errors may be either `Expired` if the timeout expired, or the inner service\'s\n///     // `Error` type. Therefore, we return a boxed `dyn Error + Send + Sync` trait object to erase\n///     // the error\'s type.\n///     type Error = Box<dyn Error + Send + Sync>;\n///     type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>>>>;\n///\n///     fn poll_ready(&mut self, cx: &mut Context<\'_>) -> Poll<Result<(), Self::Error>> {\n///         // Our timeout service is ready if the inner service is ready.\n///         // This is how backpressure can be propagated through a tree of nested services.\n///        self.inner.poll_ready(cx).map_err(Into::into)\n///     }\n///\n///     fn call(&mut self, req: Request) -> Self::Future {\n///         // Create a future that completes after `self.timeout`\n///         let timeout = tokio::time::sleep(self.timeout);\n///\n///         // Call the inner service and get a future that resolves to the response\n///         let fut = self.inner.call(req);\n///\n///         // Wrap those two futures in another future that completes when either one completes\n///         //\n///         // If the inner service is too slow the `sleep` future will complete first\n///         // And an error will be returned and `fut` will be dropped and not polled again\n///         //\n///         // We have to box the errors so the types match\n///         let f = async move {\n///             tokio::select! {\n///                 res = fut => {\n///                     res.map_err(|err| err.into())\n///                 },\n///                 _ = timeout => {\n///                     Err(Box::new(Expired) as Box<dyn Error + Send + Sync>)\n///                 },\n///             }\n///         };\n///\n///         Box::pin(f)\n///     }\n/// }\n///\n/// // A layer for wrapping services in `Timeout`\n/// pub struct TimeoutLayer(Duration);\n///\n/// impl TimeoutLayer {\n///     pub fn new(delay: Duration) -> Self {\n///         TimeoutLayer(delay)\n///     }\n/// }\n///\n/// impl<S> Layer<S> for TimeoutLayer {\n///     type Service = Timeout<S>;\n///\n///     fn layer(&self, service: S) -> Timeout<S> {\n///         Timeout::new(service, self.0)\n///     }\n/// }\n/// ```\n///\n/// The above timeout implementation is decoupled from the underlying protocol\n/// and is also decoupled from client or server concerns. In other words, the\n/// same timeout middleware could be used in either a client or a server.\n///\n/// # Backpressure\n///\n/// Calling a `Service` which is at capacity (i.e., it is temporarily unable to process a\n/// request) should result in an error. The caller is responsible for ensuring\n/// that the service is ready to receive the request before calling it.\n///\n/// `Service` provides a mechanism by which the caller is able to coordinate\n/// readiness. `Service::poll_ready` returns `Ready` if the service expects that\n/// it is able to process a request.\n///\n/// # Be careful when cloning inner services\n///\n/// Services are permitted to panic if `call` is invoked without obtaining `Poll::Ready(Ok(()))`\n/// from `poll_ready`. You should therefore be careful when cloning services for example to move\n/// them into boxed futures. Even though the original service is ready, the clone might not be.\n///\n/// Therefore this kind of code is wrong and might panic:\n///\n/// ```rust\n/// # use std::pin::Pin;\n/// # use std::task::{Poll, Context};\n/// # use std::future::Future;\n/// # use tower_service::Service;\n/// #\n/// struct Wrapper<S> {\n///     inner: S,\n/// }\n///\n/// impl<R, S> Service<R> for Wrapper<S>\n/// where\n///     S: Service<R> + Clone + \'static,\n///     R: \'static,\n/// {\n///     type Response = S::Response;\n///     type Error = S::Error;\n///     type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>>>>;\n///\n///     fn poll_ready(&mut self, cx: &mut Context<\'_>) -> Poll<Result<(), Self::Error>> {\n///         Poll::Ready(Ok(()))\n///     }\n///\n///     fn call(&mut self, req: R) -> Self::Future {\n///         let mut inner = self.inner.clone();\n///         Box::pin(async move {\n///             // `inner` might not be ready since its a clone\n///             inner.call(req).await\n///         })\n///     }\n/// }\n/// ```\n///\n/// You should instead use [`std::mem::replace`] to take the service that was ready:\n///\n/// ```rust\n/// # use std::pin::Pin;\n/// # use std::task::{Poll, Context};\n/// # use std::future::Future;\n/// # use tower_service::Service;\n/// #\n/// struct Wrapper<S> {\n///     inner: S,\n/// }\n///\n/// impl<R, S> Service<R> for Wrapper<S>\n/// where\n///     S: Service<R> + Clone + \'static,\n///     R: \'static,\n/// {\n///     type Response = S::Response;\n///     type Error = S::Error;\n///     type Future = Pin<Box<dyn Future<Output = Result<Self::Response, Self::Error>>>>;\n///\n///     fn poll_ready(&mut self, cx: &mut Context<\'_>) -> Poll<Result<(), Self::Error>> {\n///         Poll::Ready(Ok(()))\n///     }\n///\n///     fn call(&mut self, req: R) -> Self::Future {\n///         let clone = self.inner.clone();\n///         // take the service that was ready\n///         let mut inner = std::mem::replace(&mut self.inner, clone);\n///         Box::pin(async move {\n///             inner.call(req).await\n///         })\n///     }\n/// }\n/// ```\npub trait Service<Request> {\n    /// Responses given by the service.\n    type Response;\n\n    /// Errors produced by the service.\n    type Error;\n\n    /// The future response value.\n    type Future: Future<Output = Result<Self::Response, Self::Error>>;\n\n    /// Returns `Poll::Ready(Ok(()))` when the service is able to process requests.\n    ///\n    /// If the service is at capacity, then `Poll::Pending` is returned and the task\n    /// is notified when the service becomes ready again. This function is\n    /// expected to be called while on a task. Generally, this can be done with\n    /// a simple `futures::future::poll_fn` call.\n    ///\n    /// If `Poll::Ready(Err(_))` is returned, the service is no longer able to service requests\n    /// and the caller should discard the service instance.\n    ///\n    /// Once `poll_ready` returns `Poll::Ready(Ok(()))`, a request may be dispatched to the\n    /// service using `call`. Until a request is dispatched, repeated calls to\n    /// `poll_ready` must return either `Poll::Ready(Ok(()))` or `Poll::Ready(Err(_))`.\n    fn poll_ready(&mut self, cx: &mut Context<\'_>) -> Poll<Result<(), Self::Error>>;\n\n    /// Process the request and return the response asynchronously.\n    ///\n    /// This function is expected to be callable off task. As such,\n    /// implementations should take care to not call `poll_ready`.\n    ///\n    /// Before dispatching a request, `poll_ready` must be called and return\n    /// `Poll::Ready(Ok(()))`.\n    ///\n    /// # Panics\n    ///\n    /// Implementations are permitted to panic if `call` is invoked without\n    /// obtaining `Poll::Ready(Ok(()))` from `poll_ready`.\n    fn call(&mut self, req: Request) -> Self::Future;\n}\n\nimpl<\'a, S, Request> Service<Request> for &\'a mut S\nwhere\n    S: Service<Request> + \'a,\n{\n    type Response = S::Response;\n    type Error = S::Error;\n    type Future = S::Future;\n\n    fn poll_ready(&mut self, cx: &mut Context<\'_>) -> Poll<Result<(), S::Error>> {\n        (**self).poll_ready(cx)\n    }\n\n    fn call(&mut self, request: Request) -> S::Future {\n        (**self).call(request)\n    }\n}\n\nimpl<S, Request> Service<Request> for Box<S>\nwhere\n    S: Service<Request> + ?Sized,\n{\n    type Response = S::Response;\n    type Error = S::Error;\n    type Future = S::Future;\n\n    fn poll_ready(&mut self, cx: &mut Context<\'_>) -> Poll<Result<(), S::Error>> {\n        (**self).poll_ready(cx)\n    }\n\n    fn call(&mut self, request: Request) -> S::Future {\n        (**self).call(request)\n    }\n}\n',
            'tower-test/Cargo.toml': '[package]\nname = "tower-test"\n# When releasing to crates.io:\n# - Remove path dependencies\n# - Update html_root_url.\n# - Update doc url\n#   - Cargo.toml\n#   - README.md\n# - Update CHANGELOG.md.\n# - Create "v0.1.x" git tag.\nversion = "0.4.0"\nauthors = ["Tower Maintainers <team@tower-rs.com>"]\nlicense = "MIT"\nreadme = "README.md"\nrepository = "https://github.com/tower-rs/tower"\nhomepage = "https://github.com/tower-rs/tower"\ndocumentation = "https://docs.rs/tower-test/0.4.0"\ndescription = """\nUtilities for writing client and server `Service` tests.\n"""\ncategories = ["asynchronous", "network-programming"]\nedition = "2018"\n\n[dependencies]\nfutures-util = { version = "0.3", default-features = false }\ntokio = { version = "1.0", features = ["sync"] }\ntokio-test = "0.4"\ntower-layer = { version = "0.3", path = "../tower-layer" }\ntower-service = { version = "0.3", path = "../tower-service" }\npin-project-lite = "0.2"\n\n[dev-dependencies]\ntokio = { version = "1.0", features = ["macros"] }\n',
            'tower-test/src/lib.rs': '#![doc(html_root_url = "https://docs.rs/tower-test/0.4.0")]\n#![warn(\n    missing_debug_implementations,\n    missing_docs,\n    rust_2018_idioms,\n    unreachable_pub\n)]\n#![forbid(unsafe_code)]\n#![allow(elided_lifetimes_in_paths)]\n// `rustdoc::broken_intra_doc_links` is checked on CI\n\n//! Mock `Service` that can be used in tests.\n\nmod macros;\npub mod mock;\n',
            'tower/Cargo.toml': '[package]\nname = "tower"\n# When releasing to crates.io:\n# - Remove path dependencies\n# - Update html_root_url.\n# - Update doc url\n#   - Cargo.toml\n#   - README.md\n# - Update CHANGELOG.md.\n# - Create "vX.X.X" git tag.\nversion = "0.4.11"\nauthors = ["Tower Maintainers <team@tower-rs.com>"]\nlicense = "MIT"\nreadme = "README.md"\nrepository = "https://github.com/tower-rs/tower"\nhomepage = "https://github.com/tower-rs/tower"\ndocumentation = "https://docs.rs/tower/0.4.11"\ndescription = """\nTower is a library of modular and reusable components for building robust\nclients and servers.\n"""\ncategories = ["asynchronous", "network-programming"]\nkeywords = ["io", "async", "non-blocking", "futures", "service"]\nedition = "2018"\n\n[features]\ndefault = ["log"]\nfull = [\n  "balance",\n  "buffer",\n  "discover",\n  "filter",\n  "hedge",\n  "limit",\n  "load",\n  "load-shed",\n  "make",\n  "ready-cache",\n  "reconnect",\n  "retry",\n  "spawn-ready",\n  "steer",\n  "timeout",\n  "util",\n]\nlog = ["tracing/log"]\nbalance = ["discover", "load", "ready-cache", "make", "rand", "slab", "tokio-stream"]\nbuffer = ["tokio/sync", "tokio/rt", "tokio-util", "tracing"]\ndiscover = []\nfilter = ["futures-util"]\nhedge = ["util", "filter", "futures-util", "hdrhistogram", "tokio/time", "tracing"]\nlimit = ["tokio/time", "tokio/sync", "tokio-util", "tracing"]\nload = ["tokio/time", "tracing"]\nload-shed = []\nmake = ["tokio/io-std", "futures-util"]\nready-cache = ["futures-util", "indexmap", "tokio/sync", "tracing"]\nreconnect = ["make", "tokio/io-std", "tracing"]\nretry = ["tokio/time"]\nspawn-ready = ["futures-util", "tokio/sync", "tokio/rt", "util", "tracing"]\nsteer = ["futures-util"]\ntimeout = ["tokio/time"]\nutil = ["futures-util"]\n\n[dependencies]\nfutures-core = "0.3"\npin-project = "1"\ntower-layer = { version = "0.3.1", path = "../tower-layer" }\ntower-service = { version = "0.3.1", path = "../tower-service" }\n\nfutures-util = { version = "0.3", default-features = false, features = ["alloc"], optional = true }\nhdrhistogram = { version = "7.0", optional = true }\nindexmap = { version = "1.0.2", optional = true }\nrand = { version = "0.8", features = ["small_rng"], optional = true }\nslab = { version = "0.4", optional = true }\ntokio = { version = "1", optional = true, features = ["sync"] }\ntokio-stream = { version = "0.1.0", optional = true }\ntokio-util = { version = "0.6.3", default-features = false, optional = true }\ntracing = { version = "0.1.2", default-features = false, features = ["std"], optional = true }\npin-project-lite = "0.2.7"\n\n[dev-dependencies]\nfutures = "0.3"\nhdrhistogram = "7.0"\ntokio = { version = "1", features = ["macros", "sync", "test-util", "rt-multi-thread"] }\ntokio-stream = "0.1"\ntokio-test = "0.4"\ntower-test = { version = "0.4", path = "../tower-test" }\ntracing-subscriber = "0.2.14"\nhttp = "0.2"\n\n[package.metadata.docs.rs]\nall-features = true\nrustdoc-args = ["--cfg", "docsrs"]\n\n[package.metadata.playground]\nfeatures = ["full"]\n\n[[example]]\nname = "tower-balance"\npath = "examples/tower-balance.rs"\nrequired-features = ["full"]\n',
            'tower/src/lib.rs': '#![doc(html_root_url = "https://docs.rs/tower/0.4.11")]\n#![warn(\n    missing_debug_implementations,\n    missing_docs,\n    rust_2018_idioms,\n    unreachable_pub\n)]\n#![forbid(unsafe_code)]\n#![allow(elided_lifetimes_in_paths, clippy::type_complexity)]\n#![cfg_attr(test, allow(clippy::float_cmp))]\n#![cfg_attr(docsrs, feature(doc_cfg))]\n// `rustdoc::broken_intra_doc_links` is checked on CI\n\n//! `async fn(Request) -> Result<Response, Error>`\n//!\n//! # Overview\n//!\n//! Tower is a library of modular and reusable components for building\n//! robust networking clients and servers.\n//!\n//! Tower provides a simple core abstraction, the [`Service`] trait, which\n//! represents an asynchronous function taking a request and returning either a\n//! response or an error. This abstraction can be used to model both clients and\n//! servers.\n//!\n//! Generic components, like [timeouts], [rate limiting], and [load balancing],\n//! can be modeled as [`Service`]s that wrap some inner service and apply\n//! additional behavior before or after the inner service is called. This allows\n//! implementing these components in a protocol-agnostic, composable way. Typically,\n//! such services are referred to as _middleware_.\n//!\n//! An additional abstraction, the [`Layer`] trait, is used to compose\n//! middleware with [`Service`]s. If a [`Service`] can be thought of as an\n//! asynchronous function from a request type to a response type, a [`Layer`] is\n//! a function taking a [`Service`] of one type and returning a [`Service`] of a\n//! different type. The [`ServiceBuilder`] type is used to add middleware to a\n//! service by composing it with multiple [`Layer`]s.\n//!\n//! ## The Tower Ecosystem\n//!\n//! Tower is made up of the following crates:\n//!\n//! * [`tower`] (this crate)\n//! * [`tower-service`]\n//! * [`tower-layer`]\n//! * [`tower-test`]\n//!\n//! Since the [`Service`] and [`Layer`] traits are important integration points\n//! for all libraries using Tower, they are kept as stable as possible, and\n//! breaking changes are made rarely. Therefore, they are defined in separate\n//! crates, [`tower-service`] and [`tower-layer`]. This crate contains\n//! re-exports of those core traits, implementations of commonly-used\n//! middleware, and [utilities] for working with [`Service`]s and [`Layer`]s.\n//! Finally, the [`tower-test`] crate provides tools for testing programs using\n//! Tower.\n//!\n//! # Usage\n//!\n//! Tower provides an abstraction layer, and generic implementations of various\n//! middleware. This means that the `tower` crate on its own does *not* provide\n//! a working implementation of a network client or server. Instead, Tower\'s\n//! [`Service` trait][`Service`] provides an integration point between\n//! application code, libraries providing middleware implementations, and\n//! libraries that implement servers and/or clients for various network\n//! protocols.\n//!\n//! Depending on your particular use case, you might use Tower in several ways:\n//!\n//! * **Implementing application logic** for a networked program. You might\n//!   use the [`Service`] trait to model your application\'s behavior, and use\n//!   the middleware [provided by this crate](#modules) and by other libraries\n//!   to add functionality to clients and servers provided by one or more\n//!   protocol implementations.\n//! * **Implementing middleware** to add custom behavior to network clients and\n//!   servers in a reusable manner. This might be general-purpose middleware\n//!   (and if it is, please consider releasing your middleware as a library for\n//!   other Tower users!) or application-specific behavior that needs to be\n//!   shared between multiple clients or servers.\n//! * **Implementing a network protocol**. Libraries that implement network\n//!   protocols (such as HTTP) can depend on `tower-service` to use the\n//!   [`Service`] trait as an integration point between the protocol and user\n//!   code. For example, a client for some protocol might implement [`Service`],\n//!   allowing users to add arbitrary Tower middleware to those clients.\n//!   Similarly, a server might be created from a user-provided [`Service`].\n//!\n//!   Additionally, when a network protocol requires functionality already\n//!   provided by existing Tower middleware, a protocol implementation might use\n//!   Tower middleware internally, as well as as an integration point.\n//!\n//! ## Library Support\n//!\n//! A number of third-party libraries support Tower and the [`Service`] trait.\n//! The following is an incomplete list of such libraries:\n//!\n//! * [`hyper`]: A fast and correct low-level HTTP implementation.\n//! * [`tonic`]: A [gRPC-over-HTTP/2][grpc] implementation built on top of\n//!   [`hyper`]. See [here][tonic-examples] for examples of using [`tonic`] with\n//!   Tower.\n//! * [`warp`]: A lightweight, composable web framework. See\n//!   [here][warp-service] for details on using [`warp`] with Tower.\n//! * [`tower-lsp`] and its fork, [`lspower`]: implementations of the [Language\n//!   Server Protocol][lsp] based on Tower.\n//!\n//! [`hyper`]: https://crates.io/crates/hyper\n//! [`tonic`]: https://crates.io/crates/tonic\n//! [tonic-examples]: https://github.com/hyperium/tonic/tree/master/examples/src/tower\n//! [grpc]: https://grpc.io\n//! [`warp`]: https://crates.io/crates/warp\n//! [warp-service]: https://docs.rs/warp/0.2.5/warp/fn.service.html\n//! [`tower-lsp`]: https://crates.io/crates/tower-lsp\n//! [`lspower`]: https://crates.io/crates/lspower\n//! [lsp]: https://microsoft.github.io/language-server-protocol/\n//!\n//! If you\'re the maintainer of a crate that supports Tower, we\'d love to add\n//! your crate to this list! Please [open a PR] adding a brief description of\n//! your library!\n//!\n//! ## Getting Started\n//!\n//! If you\'re brand new to Tower and want to start with the basics, we recommend you\n//! check out some of our [guides].\n//!\n//! The various middleware implementations provided by this crate are feature\n//! flagged, so that users can only compile the parts of Tower they need. By\n//! default, all the optional middleware are disabled.\n//!\n//! To get started using all of Tower\'s optional middleware, add this to your\n//! `Cargo.toml`:\n//!\n//! ```toml\n//! tower = { version = "0.4", features = ["full"] }\n//! ```\n//!\n//! Alternatively, you can only enable some features. For example, to enable\n//! only the [`retry`] and [`timeout`][timeouts] middleware, write:\n//!\n//! ```toml\n//! tower = { version = "0.4", features = ["retry", "timeout"] }\n//! ```\n//!\n//! See [here](#modules) for a complete list of all middleware provided by\n//! Tower.\n//!\n//! [`Service`]: crate::Service\n//! [`Layer`]: crate::Layer\n//! [timeouts]: crate::timeout\n//! [rate limiting]: crate::limit::rate\n//! [load balancing]: crate::balance\n//! [`ServiceBuilder`]: crate::ServiceBuilder\n//! [utilities]: crate::ServiceExt\n//! [`tower`]: https://crates.io/crates/tower\n//! [`tower-service`]: https://crates.io/crates/tower-service\n//! [`tower-layer`]: https://crates.io/crates/tower-layer\n//! [`tower-test`]: https://crates.io/crates/tower-test\n//! [`retry`]: crate::retry\n//! [open a PR]: https://github.com/tower-rs/tower/compare\n//! [guides]: https://github.com/tower-rs/tower/tree/master/guides\n\n#[macro_use]\npub(crate) mod macros;\n#[cfg(feature = "balance")]\n#[cfg_attr(docsrs, doc(cfg(feature = "balance")))]\npub mod balance;\n#[cfg(feature = "buffer")]\n#[cfg_attr(docsrs, doc(cfg(feature = "buffer")))]\npub mod buffer;\n#[cfg(feature = "discover")]\n#[cfg_attr(docsrs, doc(cfg(feature = "discover")))]\npub mod discover;\n#[cfg(feature = "filter")]\n#[cfg_attr(docsrs, doc(cfg(feature = "filter")))]\npub mod filter;\n#[cfg(feature = "hedge")]\n#[cfg_attr(docsrs, doc(cfg(feature = "hedge")))]\npub mod hedge;\n#[cfg(feature = "limit")]\n#[cfg_attr(docsrs, doc(cfg(feature = "limit")))]\npub mod limit;\n#[cfg(feature = "load")]\n#[cfg_attr(docsrs, doc(cfg(feature = "load")))]\npub mod load;\n#[cfg(feature = "load-shed")]\n#[cfg_attr(docsrs, doc(cfg(feature = "load-shed")))]\npub mod load_shed;\n\n#[cfg(feature = "make")]\n#[cfg_attr(docsrs, doc(cfg(feature = "make")))]\npub mod make;\n#[cfg(feature = "ready-cache")]\n#[cfg_attr(docsrs, doc(cfg(feature = "ready-cache")))]\npub mod ready_cache;\n#[cfg(feature = "reconnect")]\n#[cfg_attr(docsrs, doc(cfg(feature = "reconnect")))]\npub mod reconnect;\n#[cfg(feature = "retry")]\n#[cfg_attr(docsrs, doc(cfg(feature = "retry")))]\npub mod retry;\n#[cfg(feature = "spawn-ready")]\n#[cfg_attr(docsrs, doc(cfg(feature = "spawn-ready")))]\npub mod spawn_ready;\n#[cfg(feature = "steer")]\n#[cfg_attr(docsrs, doc(cfg(feature = "steer")))]\npub mod steer;\n#[cfg(feature = "timeout")]\n#[cfg_attr(docsrs, doc(cfg(feature = "timeout")))]\npub mod timeout;\n#[cfg(feature = "util")]\n#[cfg_attr(docsrs, doc(cfg(feature = "util")))]\npub mod util;\n\npub mod builder;\npub mod layer;\n\n#[cfg(feature = "util")]\n#[cfg_attr(docsrs, doc(cfg(feature = "util")))]\n#[doc(inline)]\npub use self::util::{service_fn, ServiceExt};\n\n#[doc(inline)]\npub use crate::builder::ServiceBuilder;\n#[cfg(feature = "make")]\n#[cfg_attr(docsrs, doc(cfg(feature = "make")))]\n#[doc(inline)]\npub use crate::make::MakeService;\n#[doc(inline)]\npub use tower_layer::Layer;\n#[doc(inline)]\npub use tower_service::Service;\n\n#[allow(unreachable_pub)]\nmod sealed {\n    pub trait Sealed<T> {}\n}\n\n/// Alias for a type-erased error type.\npub type BoxError = Box<dyn std::error::Error + Send + Sync>;\n',
        }
